class EventEmitter:
    def __init__(self):
        self.listeners = {}

    def on(self, event, callback):
        """Register a listener for an event."""
        if event not in self.listeners:
            self.listeners[event] = []
        self.listeners[event].append(callback)
        return self

    def off(self, event, callback=None):
        """Remove a listener for an event. If callback is not specified, remove all listeners for the event."""
        if event not in self.listeners:
            return self

        if callback is None:
            del self.listeners[event]
        else:
            if callback in self.listeners[event]:
                self.listeners[event].remove(callback)
        return self

    def emit(self, event, *args, **kwargs):
        """Trigger an event and call all registered listeners."""
        if event not in self.listeners:
            return self

        # Check for wildcard listeners on '*'
        if event == '*':
            # Emit to all events
            for event_name in self.listeners:
                for callback in self.listeners[event_name]:
                    callback(*args, **kwargs)
        else:
            # Emit to specific event
            for callback in self.listeners[event]:
                callback(*args, **kwargs)
        return self

    def on_wildcard(self, callback):
        """Register a listener for all events using wildcard '*'."""
        # Store the wildcard listener in a special key
        if '*' not in self.listeners:
            self.listeners['*'] = []
        self.listeners['*'].append(callback)
        return self

    def off_wildcard(self, callback=None):
        """Remove a wildcard listener. If callback is not specified, remove all wildcard listeners."""
        if '*' not in self.listeners:
            return self

        if callback is None:
            del self.listeners['*']
        else:
            if callback in self.listeners['*']:
                self.listeners['*'].remove(callback)
        return self
